
.phone-wrap {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  background: linear-gradient(145deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei', sans-serif;
}

.phone-frame {
  width: 100%;
  max-width: 375px;
  height: 720px;
  max-height: 85vh;
  background: #0d0d0d;
  border-radius: 36px;
  box-shadow:
    0 0 0 3px #2a2a2a,
    0 0 0 6px #1a1a1a,
    0 24px 48px rgba(0, 0, 0, 0.5),
    inset 0 0 0 1px rgba(255, 255, 255, 0.06);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  position: relative;
}

/* 刘海 */
.notch {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 140px;
  height: 28px;
  background: #0d0d0d;
  border-radius: 0 0 18px 18px;
  z-index: 10;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
}

.notch-camera {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: #1a1a2e;
  border: 2px solid #2a2a2a;
}

.notch-speaker {
  width: 50px;
  height: 6px;
  border-radius: 3px;
  background: #1a1a1a;
}

/* 状态栏 */
.status-bar {
  flex-shrink: 0;
  height: 44px;
  padding: 12px 20px 8px;
  padding-top: 36px; /* 为刘海留空 */
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: #0d0d0d;
  color: rgba(255, 255, 255, 0.7);
  font-size: 14px;
  font-weight: 600;
}

.status-dots {
  font-size: 12px;
  letter-spacing: 2px;
}

/* 聊天主屏 */
.chat-screen {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: #1c1c1e;
  border-radius: 24px 24px 0 0;
  overflow: hidden;
}

.chat-header {
  padding: 12px 16px 8px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(30, 30, 32, 0.98);
}

.chat-title {
  display: block;
  font-size: 11px;
  color: rgba(255, 255, 255, 0.5);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.chat-subtitle {
  font-size: 18px;
  font-weight: 600;
  color: #fff;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 12px 16px 16px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.msg-bubble {
  padding: 12px 14px;
  border-radius: 16px;
  max-width: 92%;
  align-self: flex-start;
  background: rgba(50, 50, 54, 0.9);
  border: 1px solid rgba(255, 255, 255, 0.06);
}

.msg-sys {
  background: rgba(40, 42, 48, 0.95);
  border-radius: 14px 14px 14px 4px;
}

.bubble-label {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.45);
  margin-bottom: 4px;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}

.bubble-value {
  font-size: 14px;
  color: rgba(255, 255, 255, 0.92);
  line-height: 1.4;
}

.dep-bar-wrap {
  height: 8px;
  border-radius: 4px;
  background: rgba(0, 0, 0, 0.35);
  overflow: hidden;
  margin: 8px 0 6px;
}

.dep-bar {
  height: 100%;
  border-radius: 4px;
  background: linear-gradient(90deg, #5e5ce6, #af52de);
  transition: width 0.3s ease;
}

.event-item,
.title-item,
.attire-item {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.85);
  margin-top: 6px;
  line-height: 1.45;
}

.event-name,
.title-name {
  color: rgba(255, 255, 255, 0.6);
  margin-right: 4px;
}

.attire-item {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.75);
}

/* 底部输入栏 */
.chat-footer {
  flex-shrink: 0;
  padding: 10px 16px 24px;
  padding-bottom: max(24px, env(safe-area-inset-bottom));
  background: rgba(28, 28, 30, 0.98);
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.input-placeholder {
  height: 40px;
  border-radius: 20px;
  background: rgba(60, 60, 64, 0.8);
  color: rgba(255, 255, 255, 0.4);
  font-size: 15px;
  display: flex;
  align-items: center;
  padding: 0 18px;
}
